import { GoogleGenAI, Modality } from "@google/genai";
import { decode, decodeAudioData } from "../utils/audioUtils";

export type VoiceSpeed = 'slow' | 'normal' | 'fast';

export const generateStoryAudio = async (
  text: string, 
  audioContext: AudioContext, 
  speed: VoiceSpeed = 'normal'
): Promise<AudioBuffer | null> => {
  // Always create a new instance to use the most up-to-date API key
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let mood = "in modo dolce, pacato e rassicurante";
  if (speed === 'slow') {
    mood = "molto lentamente, con lunghe pause rilassanti";
  } else if (speed === 'fast') {
    mood = "in modo fluido e chiaro, con un ritmo leggermente sostenuto";
  }

  // Simplified prompt structure to avoid 500 errors in preview models
  const fullPrompt = `Leggi questa storia con una voce femminile ${mood}: ${text}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: fullPrompt }] }],
      config: {
        // systemInstruction is omitted here for stability in preview TTS
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName: 'Kore' },
          },
        },
      },
    });

    // Safer way to find the audio data part
    const audioPart = response.candidates?.[0]?.content?.parts?.find(p => p.inlineData);
    const base64Audio = audioPart?.inlineData?.data;

    if (base64Audio) {
      const decodedBytes = decode(base64Audio);
      // Gemini TTS raw PCM is 24kHz mono
      const audioBuffer = await decodeAudioData(
        decodedBytes,
        audioContext,
        24000,
        1
      );
      return audioBuffer;
    }

    return null;
  } catch (error: any) {
    console.error("Gemini TTS Error:", error);
    // If the error is 404/NotFound, it might be an API Key issue
    if (error?.message?.includes("Requested entity was not found")) {
      throw new Error("API_KEY_ERROR");
    }
    throw error;
  }
};

